WITH weak_pairs AS (SELECT f.Carrier, f.OriginCode, count() AS winter_flights, round(avg(if(f.DepDel15 = 0, 1.0, 0.0)) * 100, 2) AS dep_otp_pct, round(avg(ifNull(toFloat64(f.DepDelay), 0.0)), 2) AS avg_dep_delay_min, sum(ifNull(toUInt64(f.WeatherDelay), 0)) AS weather_delay_min, sum(ifNull(toUInt64(f.CarrierDelay), 0)) AS carrier_delay_min, sum(ifNull(toUInt64(f.NASDelay), 0)) AS nas_delay_min, sum(ifNull(toUInt64(f.SecurityDelay), 0)) AS security_delay_min, sum(ifNull(toUInt64(f.LateAircraftDelay), 0)) AS late_aircraft_delay_min, countIf((f.CarrierDelay IS NOT NULL) OR (f.WeatherDelay IS NOT NULL) OR (f.NASDelay IS NOT NULL) OR (f.SecurityDelay IS NOT NULL) OR (f.LateAircraftDelay IS NOT NULL)) AS flights_with_any_reported_cause, countIf((f.CarrierDelay IS NULL) AND (f.WeatherDelay IS NULL) AND (f.NASDelay IS NULL) AND (f.SecurityDelay IS NULL) AND (f.LateAircraftDelay IS NULL)) AS flights_without_reported_cause FROM ontime.fact_ontime AS f WHERE f.Month IN (12, 1, 2) AND f.Cancelled = 0 AND f.Diverted = 0 GROUP BY f.Carrier, f.OriginCode HAVING winter_flights >= 1000 ORDER BY dep_otp_pct ASC, avg_dep_delay_min DESC LIMIT 10) SELECT Carrier, OriginCode, winter_flights, dep_otp_pct, avg_dep_delay_min, flights_with_any_reported_cause, flights_without_reported_cause, weather_delay_min, carrier_delay_min, nas_delay_min, security_delay_min, late_aircraft_delay_min, weather_delay_min + carrier_delay_min + nas_delay_min + security_delay_min + late_aircraft_delay_min AS total_reported_cause_min, round(weather_delay_min * 100.0 / nullIf(weather_delay_min + carrier_delay_min + nas_delay_min + security_delay_min + late_aircraft_delay_min, 0), 1) AS weather_share_pct, round((carrier_delay_min + nas_delay_min + security_delay_min + late_aircraft_delay_min) * 100.0 / nullIf(weather_delay_min + carrier_delay_min + nas_delay_min + security_delay_min + late_aircraft_delay_min, 0), 1) AS operational_share_pct FROM weak_pairs ORDER BY dep_otp_pct ASC, avg_dep_delay_min DESC, winter_flights DESC
